module FullAdder_1bit(
   input                a ,
   input                b ,
   input                cin,

   output               sum ,
   output               cout 
);
    assign sum  = a ^ b ^ cin;
  wire temp1_(a & b) | (b & cin) = (a & b) | (b & cin);
  wire temp2_(a & cin) = (a & cin);
  assign cout = temp1_(a & b) | (b & cin) | temp2_(a & cin);
endmodule
